import { useParams, Link } from "react-router-dom";
import Card from "../components/Card";

export default function RoadmapPage() {
  const { name } = useParams();

  const domainKey = (name || localStorage.getItem("selectedDomain") || "ai-and-ml").toLowerCase();

  if (name) {
    localStorage.setItem("selectedDomain", domainKey);
  }

  const timeline = localStorage.getItem("timeline") || "3 months";
  const totalDays = parseInt(timeline) * 30;

  const currentDay = parseInt(localStorage.getItem("currentDay") || "1");

  const topicMap = {
    "ai-and-ml": [
      ["Python Basics → Datatypes (int, float, string)"],
      ["Variables & Input/Output"],
      ["Loops (for, while)", "Conditions (if, else)"],
      ["Functions (def, return)"],
      ["NumPy → Arrays, Indexing"],
      ["Pandas → DataFrames"],
      ["Visualization → Matplotlib"],
      ["Statistics → Mean, Median"],
      ["ML → Linear Regression"],
      ["Model Evaluation → Accuracy"],
      ["Deep Learning → Neural Networks"],
      ["Project → Build ML Model"]
    ],

    "web-development": [
      ["HTML → Tags, Structure"],
      ["CSS → Selectors, Box Model"],
      ["Flexbox, Grid"],
      ["JavaScript → Variables"],
      ["Functions, DOM"],
      ["ES6 → Arrow Functions"],
      ["React → Components"],
      ["Hooks (useState)"],
      ["API → Fetch"],
      ["Node.js → Express"],
      ["MongoDB → CRUD"],
      ["Project → Full Stack"]
    ]
  };

  const topics = topicMap[domainKey] || [["Learn fundamentals"]];

  // ✅ FIXED: each day different topic
  const getTasksForDay = (day) => {
    const index = (day - 1) % topics.length; // 🔥 FIX
    const baseTasks = topics[index] || [];

    if (day === currentDay) {
      const carry = JSON.parse(localStorage.getItem("carryForward") || "[]");
      return [...new Set([...carry, ...baseTasks])];
    }

    return baseTasks;
  };

  // 🔥 Generate roadmap
  const roadmap = [];
  for (let i = 1; i <= totalDays; i++) {
    roadmap.push({
      day: i,
      tasks: getTasksForDay(i)
    });
  }

  return (
    <div className="space-y-8">
      <Card
        title={`${domainKey.replace(/-/g, " ")} Roadmap`}
        description={`Day ${currentDay} of ${totalDays}`}
      >

        {/* Back */}
        <div className="mb-6">
          <Link to="/domains" className="text-blue-600 underline text-sm">
            ← Back to Domains
          </Link>
        </div>

        {/* WEEK VIEW */}
        {Array.from({ length: Math.ceil(totalDays / 7) }).map((_, weekIndex) => {

          const startDay = weekIndex * 7 + 1;
          const endDay = Math.min(startDay + 6, totalDays);

          return (
            <div key={weekIndex} className="mb-6">

              <h3 className="text-lg font-semibold mb-3">
                📅 Week {weekIndex + 1}
              </h3>

              <div className="space-y-2">
                {roadmap.slice(startDay - 1, endDay).map((item) => (
                  <div
                    key={item.day}
                    className={`rounded-xl p-4 ${
                      item.day === currentDay
                        ? "bg-teal-200 dark:bg-teal-700"
                        : "bg-green-100 dark:bg-slate-700"
                    }`}
                  >
                    <strong>Day {item.day} → </strong>
                    {item.tasks.join(", ")}
                  </div>
                ))}
              </div>

            </div>
          );
        })}

        {/* Go to Tasks */}
        <div className="mt-6">
          <Link to="/tasks">
            <button className="px-4 py-2 bg-teal-500 text-white rounded-lg">
              Go to Tasks
            </button>
          </Link>
        </div>

      </Card>
    </div>
  );
}
